)
@Preview(
    name = "Offline Screen Dark Mode",
    showBackground = true,
    uiMode = Configuration.UI_MODE_NIGHT_YES,
)
private fun OfflineScreenPreview() {
    val content: @Composable () -> Unit = @Composable {
        OfflineView()
    }
    ScreenWithTopBar(
        title = "Title",
        content = content,
        onCloseClick = {},
        isScrollable = false
    )
}"}

