{"file_path":"/project/WordPress/src/main/java/org/wordpress/android/ui/mediapicker/loader/GifMediaDataSource.kt","content":"package org.wordpress.android.ui.mediapicker.loader

import android.content.Context
import com.tenor.android.core.constant.MediaCollectionFormat
import com.tenor.android.core.model.impl.Result
import org.wordpress.android.R
import org.wordpress.android.ui.mediapicker.MediaItem
import org.wordpress.android.ui.mediapicker.MediaItem.Identifier.GifMediaIdentifier
import org.wordpress.android.ui.mediapicker.MediaType.IMAGE
import org.wordpress.android.ui.mediapicker.loader.MediaSource.MediaLoadingResult
import org.wordpress.android.ui.mediapicker.loader.MediaSource.MediaLoadingResult.Empty
import org.wordpress.android.ui.mediapicker.loader.MediaSource.MediaLoadingResult.Failure
import org.wordpress.android.ui.mediapicker.loader.MediaSource.MediaLoadingResult.Success
import org.wordpress.android.ui.utils.UiString.UiStringRes
import org.wordpress.android.ui.utils.UiString.UiStringText
import org.wordpress.android.util.NetworkUtilsWrapper
import org.wordpress.android.util.UriUtilsWrapper
import javax.inject.Inject
import kotlin.coroutines.resume
import kotlin.coroutines.suspendCoroutine

class GifMediaDataSource
@Inject constructor(
    private val context: Context,
    private val tenorClient: TenorGifClient,
    private val uriUtilsWrapper: UriUtilsWrapper,
    private val networkUtilsWrapper: NetworkUtilsWrapper
) : MediaSource {
    private var nextPosition: Int = 0
    private val items = mutableListOf<MediaItem>()
    private var lastFilter: String? = null

    override suspend fun load(forced: Boolean, loadMore: Boolean, filter: String?): MediaLoadingResult {
        if (!loadMore) {
            lastFilter = filter
            items.clear()
            nextPosition = 0
        }

        if (!networkUtilsWrapper.isNetworkAvailable()) {
            return Failure(
                UiStringRes(R.string.no_network_title),
                image = R.drawable.img_illustration_cloud_off_152dp,
                data = items
            )
        }

        return if (!filter.isNullOrBlank()) {
            suspendCoroutine { cont ->
                tenorClient.search(filter,
                    nextPosition,
                    PAGE_SIZE,
                    onSuccess = { response ->
                        val gifList = response.results.map { it.toMediaItem() }

                        items.addAll(gifList)
                        val newPosition = response.next.toIntOrNull() ?: 0
                        val hasMore = newPosition > nextPosition
                        nextPosition = newPosition
                        val result = if (items.isNotEmpty()) {
                            Success(items.toList(), hasMore)
                        } else {
                            Empty(UiStringRes(R.string.gif_picker_empty_search_list))
                        }
                        cont.resume(result)
                    },
                    onFailure = {
                        val errorMessage = it?.message
                            ?: context.getString(R.string.gif_list_search_returned_unknown_error)
                        cont.resume(
                            Failure(
                                UiStringRes(R.string.media_loading_failed),
                                htmlSubtitle = UiStringText(errorMessage),
                                image = R.drawable.img_illustration_cloud_off_152dp,
                                data = items
                            )
                        )
                    }
                )
            }
        } else {
            buildDefaultScreen()
        }
    }

    private fun buildDefaultScreen(): MediaLoadingResult {
        val title = UiStringRes(R.string.gif_picker_initial_empty_text)
        return Empty(
            title,
            null,
            R.drawable.img_illustration_media_105dp,
            R.drawable.img_tenor_100dp,
            UiStringRes(R.string.gif_powered_by_tenor)
        )
    }

    private fun Result.toMediaItem() = MediaItem(
        identifier = GifMediaIdentifier(
            uriUtilsWrapper.parse(urlFromCollectionFormat(MediaCollectionFormat.GIF)),
            title
        ),
        url = uriUtilsWrapper.parse(urlFromCollectionFormat(MediaCollectionFormat.GIF_NANO)).toString(),
        type = IMAGE,
        dataModified = 0
    )

    private fun Result.urlFromCollectionFormat(format: String) =
        medias.firstOrNull()?.get(format)?.url

    companion object {
        private const val PAGE_SIZE = 36
    }
}"}

{"file_path":"/project/WordPress/src/main/java/org/wordpress/android/ui/mediapicker/loader/MediaLibraryDataSource.kt","content":"package org.wordpress.android.ui.mediapicker.loader

import kotlinx.coroutines.CoroutineDispatcher
import kotlinx.coroutines.async
import kotlinx.coroutines.awaitAll
import kotlinx.coroutines.withContext
import org.greenrobot.eventbus.Subscribe
import org.greenrobot.eventbus.ThreadMode.MAIN
import org.wordpress.android.R
import org.wordpress.android.fluxc.Dispatcher
import org.wordpress.android.fluxc.generated.MediaActionBuilder
import org.wordpress.android.fluxc.model.MediaModel
import org.wordpress.android.fluxc.model.SiteModel
import org.wordpress.android.fluxc.store.MediaStore
import org.wordpress.android.fluxc.store.MediaStore.FetchMediaListPayload
import org.wordpress.android.fluxc.store.MediaStore.OnMediaListFetched
import org.wordpress.android.fluxc.utils.MimeType
import org.wordpress.android.modules.BG_THREAD
import org.wordpress.android.ui.mediapicker.MediaItem
import org.wordpress.android.ui.mediapicker.MediaItem.Identifier.RemoteId
import org.wordpress.android.ui.mediapicker.MediaType
import org.wordpress.android.ui.mediapicker.MediaType.AUDIO
import org.wordpress.android.ui.mediapicker.MediaType.DOCUMENT
import org.wordpress.android.ui.mediapicker.MediaType.IMAGE
import org.wordpress.android.ui.mediapicker.MediaType.VIDEO
import org.wordpress.android.ui.mediapicker.loader.MediaSource.MediaLoadingResult
import org.wordpress.android.ui.mediapicker.loader.MediaSource.MediaLoadingResult.Empty
import org.wordpress.android.ui.mediapicker.loader.MediaSource.MediaLoadingResult.Failure
import org.wordpress.android.ui.utils.UiString.UiStringRes
import org.wordpress.android.ui.utils.UiString.UiStringText
import org.wordpress.android.util.DateTimeUtilsWrapper
import org.wordpress.android.util.NetworkUtilsWrapper
import javax.inject.Inject
import javax.inject.Named
import kotlin.coroutines.Continuation
import kotlin.coroutines.resume
import kotlin.coroutines.suspendCoroutine

@Suppress("LongParameterList")
class MediaLibraryDataSource(
    private val mediaStore: MediaStore,
    private val dispatcher: Dispatcher,
    @param:Named(BG_THREAD) private val bgDispatcher: CoroutineDispatcher,
    private val networkUtilsWrapper: NetworkUtilsWrapper,
    private val dateTimeUtilsWrapper: DateTimeUtilsWrapper,
    private val siteModel: SiteModel,
    override val mediaTypes: Set<MediaType>
) : MediaSource, MediaSourceWithTypes {
    init {
        dispatcher.register(this)
    }

    private var loadContinuations = mutableMapOf<MimeType.Type, Continuation<OnMediaListFetched>>()

    override suspend fun load(
        forced: Boolean,
        loadMore: Boolean,
        filter: String?
    ): MediaLoadingResult {
        if (!networkUtilsWrapper.isNetworkAvailable()) {
            return Failure(
                UiStringRes(R.string.no_network_title),
                image = R.drawable.img_illustration_cloud_off_152dp,
                data = if (loadMore) get(mediaTypes, filter) else listOf()
            )
        }
        return withContext(bgDispatcher) {
            val loadingResults = mediaTypes.map { mediaType ->
                async {
                    loadPage(
                        siteModel,
                        loadMore,
                        mediaType.toMimeType()
                    )
                }
            }.awaitAll()

            var error: String? = null
            var hasMore = false
            for (loadingResult in loadingResults) {
                if (loadingResult.isError) {
                    error = loadingResult.error.message
                    break
                } else {
                    hasMore = hasMore || loadingResult.canLoadMore
                }
            }
            if (error != null) {
                Failure(
                    UiStringRes(R.string.media_loading_failed),
                    htmlSubtitle = UiStringText(error),
                    image = R.drawable.img_illustration_cloud_off_152dp,
                    data = if (loadMore) get(mediaTypes, filter) else listOf()
                )
            } else {
                val data = get(mediaTypes, filter)
                if (filter.isNullOrEmpty() || data.isNotEmpty()) {
                    MediaLoadingResult.Success(data, hasMore)
                } else {
                    Empty(
                        UiStringRes(R.string.media_empty_search_list),
                        image = R.drawable.img_illustration_empty_results_216dp
                    )
                }
            }
        }
    }

    private suspend fun get(mediaTypes: Set<MediaType>, filter: String?): List<MediaItem> {
        return withContext(bgDispatcher) {
            mediaTypes.map { mediaType ->
                async {
                    if (filter == null) {
                        getFromDatabase(mediaType)
                    } else {
                        searchInDatabase(mediaType, filter)
                    }
                }
            }.fold(mutableListOf<MediaItem>()) { result, databaseItems ->
                result.addAll(databaseItems.await())
                result
            }.sortedByDescending { it.dataModified }
        }
    }

    private fun List<MediaModel>.toMediaItems(mediaType: MediaType): List<MediaItem> {
        return this.filter { it.url.isNotBlank() }.map { mediaModel ->
            MediaItem(
                RemoteId(mediaModel.mediaId),
                mediaModel.url,
                mediaModel.title,
                mediaType,
                mediaModel.mimeType,
                mediaModel.uploadDate?.let { dateTimeUtilsWrapper.dateFromIso8601(it).time } ?: 0L
            )
        }
    }

    private fun getFromDatabase(mediaType: MediaType): List<MediaItem> {
        return when (mediaType) {
            IMAGE -> mediaStore.getSiteImages(siteModel)
            VIDEO -> mediaStore.getSiteVideos(siteModel)
            AUDIO -> mediaStore.getSiteAudio(siteModel)
            DOCUMENT -> mediaStore.getSiteDocuments(siteModel)
        }.toMediaItems(mediaType)
    }

    private fun searchInDatabase(mediaType: MediaType, filter: String): List<MediaItem> {
        return when (mediaType) {
            IMAGE -> mediaStore.searchSiteImages(siteModel, filter)
            VIDEO -> mediaStore.searchSiteVideos(siteModel, filter)
            AUDIO -> mediaStore.searchSiteAudio(siteModel, filter)
            DOCUMENT -> mediaStore.searchSiteDocuments(siteModel, filter)
        }.toMediaItems(mediaType)
    }

    private suspend fun loadPage(siteModel: SiteModel, loadMore: Boolean, filter: MimeType.Type): OnMediaListFetched =
        suspendCoroutine { cont ->
            loadContinuations[filter] = cont
            val payload = FetchMediaListPayload(
                siteModel,
                NUM_MEDIA_PER_FETCH,
                loadMore,
                filter
            )
            dispatcher.dispatch(MediaActionBuilder.newFetchMediaListAction(payload))
        }

    private fun MediaType.toMimeType(): MimeType.Type {
        return when (this) {
            IMAGE -> MimeType.Type.IMAGE
            VIDEO -> MimeType.Type.VIDEO
            AUDIO -> MimeType.Type.AUDIO
            DOCUMENT -> MimeType.Type.APPLICATION
        }
    }

    @Subscribe(threadMode = MAIN)
    fun onMediaListFetched(event: OnMediaListFetched) {
        loadContinuations[event.mimeType]?.resume(event)
        loadContinuations.remove(event.mimeType)
    }

    companion object {
        const val NUM_MEDIA_PER_FETCH = 24
    }

    class MediaLibraryDataSourceFactory
    @Inject constructor(
        private val mediaStore: MediaStore,
        private val dispatcher: Dispatcher,
        @param:Named(BG_THREAD) private val bgDispatcher: CoroutineDispatcher,
        private val networkUtilsWrapper: NetworkUtilsWrapper,
        private val dateTimeUtilsWrapper: DateTimeUtilsWrapper
    ) {
        fun build(siteModel: SiteModel, mediaTypes: Set<MediaType>) =
            MediaLibraryDataSource(
                mediaStore,
                dispatcher,
                bgDispatcher,
                networkUtilsWrapper,
                dateTimeUtilsWrapper,
                siteModel,
                mediaTypes
            )
    }
}"}

{"file_path":"/project/WordPress/src/main/java/org/wordpress/android/ui/mediapicker/loader/StockMediaDataSource.kt","content":"package org.wordpress.android.ui.mediapicker.loader

import kotlinx.coroutines.CoroutineDispatcher
import kotlinx.coroutines.withContext
import org.wordpress.android.R
import org.wordpress.android.fluxc.store.StockMediaStore
import org.wordpress.android.modules.BG_THREAD
import org.wordpress.android.ui.mediapicker.MediaItem
import org.wordpress.android.ui.mediapicker.MediaItem.Identifier.StockMediaIdentifier
import org.wordpress.android.ui.mediapicker.MediaType.IMAGE
import org.wordpress.android.ui.mediapicker.loader.MediaSource.MediaLoadingResult
import org.wordpress.android.ui.mediapicker.loader.MediaSource.MediaLoadingResult.Empty
import org.wordpress.android.ui.mediapicker.loader.MediaSource.MediaLoadingResult.Failure
import org.wordpress.android.ui.mediapicker.loader.MediaSource.MediaLoadingResult.Success
import org.wordpress.android.ui.utils.UiString.UiStringRes
import org.wordpress.android.ui.utils.UiString.UiStringResWithParams
import org.wordpress.android.ui.utils.UiString.UiStringText
import org.wordpress.android.util.NetworkUtilsWrapper
import javax.inject.Inject
import javax.inject.Named

class StockMediaDataSource
@Inject constructor(
    private val stockMediaStore: StockMediaStore,
    @param:Named(BG_THREAD) private val bgDispatcher: CoroutineDispatcher,
    private val networkUtilsWrapper: NetworkUtilsWrapper
) : MediaSource {
    override suspend fun load(
        forced: Boolean,
        loadMore: Boolean,
        filter: String?
    ): MediaLoadingResult {
        if (!networkUtilsWrapper.isNetworkAvailable()) {
            return Failure(
                UiStringRes(R.string.no_network_title),
                image = R.drawable.img_illustration_cloud_off_152dp,
                data = if (loadMore) get() else listOf()
            )
        }
        return withValidFilter(filter) { validFilter ->
            val result = stockMediaStore.fetchStockMedia(validFilter, loadMore)
            val error = result.error
            return@withValidFilter when {
                error != null -> {
                    Failure(
                        UiStringRes(R.string.media_loading_failed),
                        htmlSubtitle = UiStringText(error.message),
                        image = R.drawable.img_illustration_cloud_off_152dp,
                        data = get()
                    )
                }
                else -> {
                    val data = get()
                    if (data.isNotEmpty()) {
                        Success(data, result.canLoadMore)
                    } else {
                        Empty(
                            UiStringRes(R.string.media_empty_search_list),
                            image = R.drawable.img_illustration_empty_results_216dp
                        )
                    }
                }
            }
        } ?: buildDefaultScreen()
    }

    private fun buildDefaultScreen(): MediaLoadingResult {
        val title = UiStringRes(R.string.stock_media_picker_initial_empty_text)
        val link = "<a href='https://pexels.com/'>Pexels</a>"
        val subtitle = UiStringResWithParams(
            R.string.stock_media_picker_initial_empty_subtext,
            listOf(UiStringText(link))
        )
        return Empty(title, subtitle)
    }

    private suspend fun get(): List<MediaItem> {
        return stockMediaStore.getStockMedia()
            .mapNotNull {
                it.url?.let { url ->
                    MediaItem(
                        StockMediaIdentifier(it.url, it.name, it.title),
                        url,
                        it.name,
                        IMAGE,
                        null,
                        it.date?.toLongOrNull() ?: 0
                    )
                }
            }
    }

    private suspend fun <T> withValidFilter(filter: String?, action: suspend (filter: String) -> T): T? {
        return if (filter != null && filter.length >= MIN_SEARCH_QUERY_SIZE) {
            withContext(bgDispatcher) {
                action(filter)
            }
        } else {
            null
        }
    }

    companion object {
        private const val MIN_SEARCH_QUERY_SIZE = 3
    }
}"}

